const payload =
  typeof $json.body === 'string'
    ? JSON.parse($json.body)
    : $json.body;

const match = payload.doc_url.match(/\/documents\/(\d+)\/?/);

if (!match) {
  throw new Error('Dokument-ID wurde in doc_url nicht gefunden');
}

return [{
  json: {
    ...payload,
    document_id: Number(match[1]),
  },
}];

const document =
  $('Dokumentdaten und Datei zusammenführen').first().json;

return $input.all().map((item, index) => {
  const fileName =
    item.binary?.data?.fileName ??
    `page-${index + 1}.png`;

  const match = fileName.match(/page-(\d+)\.png$/i);

  return {
    json: {
      document_id: document.id,
      title: document.title ?? '',
      original_file_name:
        document.original_file_name ??
        document.filename ??
        '',

      original_content:
        document.content ?? '',

      original_custom_fields:
        Array.isArray(document.custom_fields)
          ? document.custom_fields
          : [],

      page_number:
        match
          ? Number(match[1])
          : index + 1,

      page_file_name: fileName,
    },

    binary: item.binary,
  };
});

const page =
  $('Seiten einzeln verarbeiten').item.json;

return {
  json: {
    ...page,
    image_base64: $json.image_base64,
  },
};

