function parseModelResult(value) {
  const raw = String(value ?? '').trim();

  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const candidates = [cleaned];

  /*
   * Falls das Modell vor oder nach dem JSON zusätzlichen
   * Text ausgegeben hat, wird der Bereich vom ersten {
   * bis zum letzten } zusätzlich geprüft.
   */
  const firstBrace =
    cleaned.indexOf('{');

  const lastBrace =
    cleaned.lastIndexOf('}');

  if (
    firstBrace >= 0 &&
    lastBrace > firstBrace
  ) {
    candidates.push(
      cleaned.slice(
        firstBrace,
        lastBrace + 1
      )
    );
  }

  for (const candidate of candidates) {
    try {
      return {
        parsed: true,
        data: JSON.parse(candidate),
        raw,
      };
    } catch {
      // Nächsten Kandidaten prüfen.
    }
  }

  return {
    parsed: false,
    data: {},
    raw,
  };
}

const glmInput =
  $('GLM-Ergebnis vorbereiten').item.json;

const glm =
  parseModelResult(glmInput.glm_raw);

const qwen =
  parseModelResult($json.message?.content);

return {
  json: {
    document_id:
      glmInput.document_id,

    title:
      glmInput.title,

    original_file_name:
      glmInput.original_file_name,

    // Ursprünglichen Paperless-OCR-Text behalten.
    original_content:
      glmInput.original_content,

    original_custom_fields:
      glmInput.original_custom_fields,

    page_number:
      glmInput.page_number,

    page_file_name:
      glmInput.page_file_name,

    glm_parsed:
      glm.parsed,

    glm:
      glm.data,

    glm_raw:
      glm.raw,

    qwen_parsed:
      qwen.parsed,

    qwen:
      qwen.data,

    qwen_raw:
      qwen.raw,
  },
};

const pages = $input
  .all()
  .map(item => item.json)
  .sort(
    (a, b) =>
      Number(a.page_number) -
      Number(b.page_number)
  );

function toArray(value) {
  return Array.isArray(value)
    ? value.filter(value =>
        value !== null &&
        value !== undefined &&
        String(value).trim() !== ''
      )
    : [];
}

/**
 * Bei einer erneuten Verarbeitung wird nur der tatsächlich
 * ursprüngliche Paperless-OCR-Inhalt übernommen.
 */
function extractOriginalPaperlessContent(content) {
  const value = String(content ?? '').trim();

  const marker =
    '=== Ursprünglicher Paperless-OCR-Inhalt ===';

  if (!value.includes(marker)) {
    return value;
  }

  return value
    .split(marker)
    .slice(1)
    .join(marker)
    .trim();
}

/**
 * Fallback für Modellantworten, die trotz des neuen Prompts
 * nur ein Symbol oder Emoji als String zurückgeben.
 */
const symbolNames = {
  '❤️': 'Herz',
  '❤': 'Herz',
  '♥': 'Herz',
  '♡': 'Herz',

  '△': 'Dreieck',
  '▲': 'Dreieck',
  '▽': 'Dreieck',
  '▼': 'Dreieck',

  '□': 'Quadrat',
  '■': 'Quadrat',
  '□×': 'Quadrat mit Kreuz',
  '☒': 'Quadrat mit Kreuz',
  '⊠': 'Quadrat mit Kreuz',

  '○': 'Kreis',
  '◯': 'Kreis',
  '●': 'Kreis',

  '×': 'Kreuz',
  '✕': 'Kreuz',
  '✖': 'Kreuz',

  '✓': 'Häkchen',
  '✔': 'Häkchen',

  '→': 'Pfeil nach rechts',
  '←': 'Pfeil nach links',
  '↑': 'Pfeil nach oben',
  '↓': 'Pfeil nach unten',
};

/**
 * Wandelt alte String-Antworten und neue Objekt-Antworten
 * in eine gemeinsame Struktur um.
 */
function normalizeVisualItem(value, fallbackType) {
  if (
    value === null ||
    value === undefined
  ) {
    return null;
  }

  if (typeof value === 'string') {
    const raw = value.trim();

    if (!raw) {
      return null;
    }

    return {
      type: fallbackType,
      label:
        symbolNames[raw] ??
        raw,
      symbol:
        symbolNames[raw]
          ? raw
          : '',
      text: '',
      description: '',
    };
  }

  if (typeof value === 'object') {
    return {
      type:
        String(
          value.type ??
          fallbackType
        ).trim(),

      label:
        String(
          value.label ??
          value.name ??
          ''
        ).trim(),

      symbol:
        String(
          value.symbol ??
          value.emoji ??
          value.glyph ??
          ''
        ).trim(),

      text:
        String(
          value.text ??
          value.transcription ??
          ''
        ).trim(),

      description:
        String(
          value.description ??
          value.details ??
          ''
        ).trim(),
    };
  }

  return null;
}

function formatSymbol(item) {
  const label =
    item.label ||
    symbolNames[item.symbol] ||
    'Unbekanntes Symbol';

  const parts = [label];

  if (item.symbol) {
    parts.push(`(Symbol: ${item.symbol})`);
  }

  if (item.description) {
    parts.push(`– ${item.description}`);
  }

  return parts.join(' ');
}

function formatHandwriting(item) {
  const text =
    item.text ||
    item.label ||
    item.description;

  if (!text) {
    return null;
  }

  return `${text} (handgeschriebener Text)`;
}

function formatVisualObject(item, typeLabel) {
  const mainText =
    item.label ||
    item.text ||
    typeLabel;

  const details = [];

  if (
    item.text &&
    item.text !== mainText
  ) {
    details.push(`Text: ${item.text}`);
  }

  if (item.description) {
    details.push(item.description);
  }

  if (item.symbol) {
    details.push(`Symbol: ${item.symbol}`);
  }

  if (details.length === 0) {
    return `${mainText} (${typeLabel})`;
  }

  return (
    `${mainText} (${typeLabel}: ` +
    `${details.join('; ')})`
  );
}

const textParts = [];
const tables = [];
const documentStructures = [];

/**
 * Hier werden die neuen suchbaren visuellen Beschreibungen
 * pro Seite gesammelt.
 */
const searchableVisualSections = [];

const warnings = [];

for (const page of pages) {
  const glmText =
    page.glm?.text_markdown ||
    page.glm?.text ||
    (!page.glm_parsed
      ? page.glm_raw
      : '');

  if (String(glmText ?? '').trim()) {
    textParts.push(
      `## Seite ${page.page_number}\n\n` +
      String(glmText).trim()
    );
  }

  for (
    const table of toArray(
      page.glm?.tables_markdown
    )
  ) {
    tables.push(
      `### Tabelle auf Seite ${page.page_number}\n\n` +
      String(table).trim()
    );
  }

  const structures =
    toArray(
      page.glm?.document_structure
    );

  if (structures.length > 0) {
    documentStructures.push(
      `### Struktur auf Seite ${page.page_number}\n\n` +
      structures
        .map(value => `- ${value}`)
        .join('\n')
    );
  }

  const pageVisualEntries = [];

  /*
   * Symbole und geometrische Formen
   */
  for (
    const rawSymbol of toArray(
      page.qwen?.symbols
    )
  ) {
    const item =
      normalizeVisualItem(
        rawSymbol,
        'symbol'
      );

    if (!item) {
      continue;
    }

    pageVisualEntries.push(
      formatSymbol(item)
    );
  }

  /*
   * Handschriftliche Texte
   */
  for (
    const rawHandwriting of toArray(
      page.qwen?.handwriting
    )
  ) {
    const item =
      normalizeVisualItem(
        rawHandwriting,
        'handwriting'
      );

    if (!item) {
      continue;
    }

    const formatted =
      formatHandwriting(item);

    if (formatted) {
      pageVisualEntries.push(formatted);
    }
  }

  /*
   * Stempel
   */
  for (
    const rawStamp of toArray(
      page.qwen?.stamps
    )
  ) {
    const item =
      normalizeVisualItem(
        rawStamp,
        'stamp'
      );

    if (!item) {
      continue;
    }

    pageVisualEntries.push(
      formatVisualObject(
        item,
        'Stempel'
      )
    );
  }

  /*
   * Unterschriften
   */
  for (
    const rawSignature of toArray(
      page.qwen?.signatures
    )
  ) {
    const item =
      normalizeVisualItem(
        rawSignature,
        'signature'
      );

    if (!item) {
      continue;
    }

    pageVisualEntries.push(
      formatVisualObject(
        item,
        'Unterschrift'
      )
    );
  }

  /*
   * Bilder, Fotos, Diagramme und Abbildungen
   */
  for (
    const rawImage of toArray(
      page.qwen?.images
    )
  ) {
    const item =
      normalizeVisualItem(
        rawImage,
        'image'
      );

    if (!item) {
      continue;
    }

    pageVisualEntries.push(
      formatVisualObject(
        item,
        'Bild oder Abbildung'
      )
    );
  }

  /*
   * Sonstige visuelle Hinweise
   */
  for (
    const rawNote of toArray(
      page.qwen?.visual_notes
    )
  ) {
    const item =
      normalizeVisualItem(
        rawNote,
        'visual_note'
      );

    if (!item) {
      continue;
    }

    pageVisualEntries.push(
      formatVisualObject(
        item,
        'visueller Hinweis'
      )
    );
  }

  if (pageVisualEntries.length > 0) {
    searchableVisualSections.push(
      `## Seite ${page.page_number}\n\n` +
      pageVisualEntries
        .map(
          (value, index) =>
            `${index + 1}. ${value}`
        )
        .join('\n\n')
    );
  }

  warnings.push(
    ...toArray(page.glm?.warnings),
    ...toArray(page.qwen?.warnings)
  );
}

const aiSections = [];

if (textParts.length > 0) {
  aiSections.push(
    `# Dokumenttext\n\n` +
    textParts.join('\n\n')
  );
}

if (tables.length > 0) {
  aiSections.push(
    `# Tabellen\n\n` +
    tables.join('\n\n')
  );
}

if (documentStructures.length > 0) {
  aiSections.push(
    `# Dokumentstruktur\n\n` +
    documentStructures.join('\n\n')
  );
}

if (searchableVisualSections.length > 0) {
  aiSections.push(
    `# Erkannte Symbole, visuelle Elemente und handgeschriebene Texte\n\n` +
    searchableVisualSections.join('\n\n')
  );
}

// Ausschließlich neu erzeugter KI-/Vision-Inhalt.
const aiContent =
  aiSections.join('\n\n').trim();

// Tatsächlich ursprünglicher Paperless-OCR-Inhalt.
const originalPaperlessContent =
  extractOriginalPaperlessContent(
    pages[0]?.original_content
  );

const originalSection =
  originalPaperlessContent ||
  '[Kein ursprünglicher Paperless-OCR-Inhalt vorhanden]';

// Dieser Inhalt wird später nach Paperless geschrieben.
const combinedPaperlessContent = [
  '=== KI-OCR / Vision-Ergebnis ===',
  '',
  aiContent ||
    '[Kein brauchbares KI-OCR-Ergebnis erzeugt]',
  '',
  '=== Ursprünglicher Paperless-OCR-Inhalt ===',
  '',
  originalSection,
]
  .join('\n')
  .trim();

/**
 * Qualitätsprüfung ausschließlich anhand des
 * neuen KI-/Vision-Inhalts.
 */
const normalizedAiContent =
  aiContent.toLowerCase();

const contentWithoutErrorPhrases =
  normalizedAiContent
    .replace(/\[?unlesbar\]?/gi, '')
    .replace(/keine daten/gi, '')
    .replace(/nicht erkennbar/gi, '')
    .replace(/kein text erkannt/gi, '')
    .replace(/^#+.*$/gm, '')
    .replace(/\s+/g, '');

const quality = {
  usable:
    pages.length > 0 &&
    aiContent.length >= 100 &&
    contentWithoutErrorPhrases.length >= 30,

  ai_character_count:
    aiContent.length,

  original_character_count:
    originalPaperlessContent.length,

  combined_character_count:
    combinedPaperlessContent.length,

  page_count:
    pages.length,

  glm_json_valid_for_all_pages:
    pages.every(
      page =>
        page.glm_parsed === true
    ),

  qwen_json_valid_for_all_pages:
    pages.every(
      page =>
        page.qwen_parsed === true
    ),

  markdown_table_detected:
    tables.length > 0,

  image_descriptions_present:
    searchableVisualSections.length > 0,

  warnings,
};

return [
  {
    json: {
      document_id:
        pages[0]?.document_id,

      title:
        pages[0]?.title ?? '',

      original_file_name:
        pages[0]?.original_file_name ?? '',

      original_custom_fields:
        pages[0]?.original_custom_fields ?? [],

      pages,

      ai_content:
        aiContent,

      original_paperless_content:
        originalPaperlessContent,

      combined_paperless_content:
        combinedPaperlessContent,

      quality,

      write_back: true,
    },
  },
];

const fieldId = 12;

const customFields =
  Array.isArray($json.custom_fields)
    ? $json.custom_fields
    : [];

const processedField =
  customFields.find(
    field => Number(field.field) === fieldId
  );

return {
  json: {
    ...$json,
    ki_ocr_processed:
      processedField?.value === true,
  },
};

const kiOcrFieldId = 12;

const existing =
  Array.isArray($json.original_custom_fields)
    ? $json.original_custom_fields.map(item => ({ ...item }))
    : [];

const updated = existing.filter(
  item => Number(item.field) !== kiOcrFieldId
);

updated.push({
  field: kiOcrFieldId,
  value: true,
});

return {
  json: {
    ...$json,
    updated_custom_fields: updated,
  },
};

parameters.text:
=✅ KI-OCR-Test abgeschlossen

Dokument-ID: {{$json.document_id}}
Titel: {{$json.title}}
Seiten: {{$json.quality.page_count}}

KI-Zeichen:
{{$json.quality.ai_character_count}}

Ursprüngliche OCR-Zeichen:
{{$json.quality.original_character_count}}

Gesamtzeichen:
{{$json.quality.combined_character_count}}

GLM-JSON vollständig gültig:
{{$json.quality.glm_json_valid_for_all_pages}}

Qwen-JSON vollständig gültig:
{{$json.quality.qwen_json_valid_for_all_pages}}

Tabelle erkannt:
{{$json.quality.markdown_table_detected}}

Visuelle Inhalte erkannt:
{{$json.quality.image_descriptions_present}}

--- KI-Ergebnis Vorschau ---
{{$json.ai_content.slice(0, 1800)}}

--- Ursprünglicher Paperless-Text ---
{{$json.original_paperless_content.slice(0, 600)}}
